text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        "공개 릴리스 목표는 스모크 테스트 통과 시 금요일 15:00 KST로 설정한다.",
        "릴리스는 스모크 테스트 통과가 선행되어야 하므로, 스모크 테스트를 무시하고의사결정은 할 수 없다.",
        "packageName 불일치가 발생하면 `smoke-theme-pack.mjs`를 무시하지 않고, 우선 패키지 설정/계약을 확인한다. 계약 자체가 잘못된 경우에만 스크립트를 재검토한다.",
        "Minjun은 금요일 10:00 KST까지 스모크 테스트를 다시 실행하고 결과를 공유한다.",
        "Doyun은 금요일 12:00 KST까지 실패 분석 트라이애지 노트를 `action_items.md`에 작성한다."
      ],
      "rejected_proposals": [
        "Hara가 제안한 `smoke-theme-pack.mjs`에서 packageName mismatch를 무시하도록 변경하는 방안은 채택되지 않았다."
      ]
    },
    "non_decisions": [
      "README 설치 단계 검토는 필요성이 언급되었으나, 담당자/최종 책임자는 지정되지 않았다.",
      "Hara의 tarball 경로 확인은 Minjun의 스모크 결과 공유 후 수행하되, 구체적인 기한은 설정되지 않았다."
    ],
    "internal_stretch_goals": [
      "수요일 공개 릴리스는 내부 stretch goal로만 취급되며, 최종 결정된 공개 목표는 아니다."
    ],
    "risks": [
      "잘못된 tarball 경로가 확인되면 릴리스가 지연될 수 있다.",
      "README 설치 단계가 구식일 경우, 릴리스 노트 및 사용자 안내가 오도될 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "내부 stretch goal(수요일 목표)을 릴리스 노트에 언급할지 여부는 아직 결정되지 않았다."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트라이애지 노트를 `action_items.md`에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로 확인",
      "due": "미정(결과 공유 후 즉시)",
      "status": "확정(기한 미정)",
      "source_certainty": "높음"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 최신성 점검",
      "due": "목요일(가능 시)",
      "status": "보류(담당자 미지정)",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "next_to_check": [
      "금요일 10:00 KST 이전에 Minjun의 스모크 결과를 확인해 통과/실패 여부를 기록한다.",
      "실패 시 Doyun의 트라이애지 노트(금요일 12:00 KST) 작성 완료 여부와 원인 범위를 확인한다.",
      "스모크 결과가 공유되면 Hara가 tarball 경로 검증을 수행했는지 확인한다.",
      "최종 승인 권한자 지정 여부를 별도 확정한다.",
      "수요일 stretch goal를 대외 릴리스 노트에 반영할지 여부를 결정한다.",
      "README 검토 담당자와 확인 일정을 보완한다."
    ],
    "not_to_invent": [
      "고객명, 예산, 보안 인시던트, 운영 장애, 법무 승인 요구 등 부정기록 항목은 추가하지 않는다.",
      "최종 승인 권한자, 추가 리스크, 추가 소유자, 추가 마감일은 추론해 넣지 않는다.",
      "기록에 없는 절대 날짜는 임의로 계산해 채우지 않는다."
    ]
  },
  "non_invention_rules": [
    "회의 참가자, 결정, 제안 반려, 액션 아이템, 리스크, 미결질문만 사용한다.",
    "금융/보안/법무/고객/아웃테이지(장애) 정보는 원문에 없으므로 생성하지 않는다.",
    "소유자(owner), 마감일(due) 정보는 발언에 명시된 범위(예: 미지정, 기한 미정, 가능 시)에 한해 기록한다.",
    "수치/기한은 원문에 명시된 형태를 벗어나 임의 확장하지 않는다."
  ]
}
